SELECT u.id AS userId, a.id AS accountId, a.account_name AS accountName, u.nickname AS nickname, u.email AS email FROM sys_user u LEFT JOIN sys_account a ON a.user_id = u.id AND a.status = 1 AND a.is_deleted = 0 WHERE u.id IN
#{id}
AND u.status = 1 AND u.is_deleted = 0 ORDER BY a.id ASC
